TaskConfig = {}
TaskConfig.TaskList = {}
function TaskConfig:init(config)
    for _, task in pairs(config) do
        local data = {}
        data.Id = tonumber(task.Id)
        data.NextTaskId = tonumber(task.NextTaskId)
        data.TaskTypeId = tonumber(task.TaskTypeId)
        data.GoalNum = tonumber(task.GoalNum)
        data.Remarks = task.Remarks
        data.ActiveValue=task.ActiveValue
        data.RewardIds = StringUtil.split(task.RewardIds, "#")
        data.SortValue = tonumber(task.SortValue)
        self.TaskList[data.Id] = data
    end
end

function TaskConfig:getTaskById(Id)
    return self.TaskList[tonumber(Id)]
end

return TaskConfig